parameters.functionCode:
const data = $input.first().json;

// Check required fields
const required = ['caller_name', 'phone', 'case_type'];
const missing = required.filter(f => !data[f]);

if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

// Normalize phone number
let phone = (data.phone || '').replace(/[^\d+]/g, '');
if (!phone.startsWith('+')) phone = '+1' + phone;

return [{
  json: {
    call_id: data.call_id || `manual_${Date.now()}`,
    caller_name: (data.caller_name || '').trim(),
    phone: phone,
    email: (data.email || '').trim().toLowerCase(),
    case_type: data.case_type,
    case_description: (data.case_description || '').trim(),
    urgency: data.urgency || 'low',
    jurisdiction: (data.jurisdiction || '').trim(),
    injuries: data.injuries || false,
    court_date: data.court_date || null,
    existing_representation: data.existing_representation || false,
    qualified: data.qualified,
    qualification_reason: data.qualification_reason || '',
    transcript: data.transcript || '',
    duration_seconds: data.duration_seconds || 0,
    additional_notes: data.additional_notes || '',
    processed_at: new Date().toISOString()
  }
}];

const lead = $node['Validate Payload'].first().json;
const dedupEntries = $node['Read Dedup Tracker'].all();

// Check for exact call_id match
const callIdMatch = dedupEntries.find(e => e.json.call_id === lead.call_id);
if (callIdMatch) {
  return [{ json: { ...lead, action: 'skip', skip_reason: 'Duplicate call_id' } }];
}

// Check for same phone within 24 hours
const now = Date.now();
const windowMs = 24 * 60 * 60 * 1000;
const phoneMatch = dedupEntries.find(e => {
  return e.json.phone === lead.phone &&
    (now - new Date(e.json.timestamp).getTime()) < windowMs;
});

if (phoneMatch) {
  return [{ json: { ...lead, action: 'update', skip_reason: 'Recent call from same number' } }];
}

return [{ json: { ...lead, action: 'create' } }];

const data = $input.first().json;
const practiceAreas = ['personal_injury', 'family_law', 'criminal_defense', 'employment_law'];
const serviceAreas = ['california', 'ca'];

// HARD DISQUALIFIERS (override AI)
if (!practiceAreas.includes(data.case_type)) {
  return [{ json: { ...data, qualified: false, qualification_reason: `Case type "${data.case_type}" outside practice areas`, qualification_source: 'rules_engine' } }];
}
if (data.existing_representation === true) {
  return [{ json: { ...data, qualified: false, qualification_reason: 'Caller already has legal representation', qualification_source: 'rules_engine' } }];
}
const jurisdiction = (data.jurisdiction || '').toLowerCase();
if (jurisdiction && !serviceAreas.some(a => jurisdiction.includes(a))) {
  return [{ json: { ...data, qualified: false, qualification_reason: `Outside service jurisdiction: ${data.jurisdiction}`, qualification_source: 'rules_engine' } }];
}

// HARD QUALIFIERS (override AI if it missed)
if (data.urgency === 'high') {
  return [{ json: { ...data, qualified: true, qualification_reason: data.qualification_reason || 'Urgent case in practice area', qualification_source: 'rules_override' } }];
}
if (data.case_type === 'personal_injury' && data.injuries === true) {
  return [{ json: { ...data, qualified: true, qualification_reason: data.qualification_reason || 'PI case with reported injuries', qualification_source: 'rules_override' } }];
}
if (data.case_type === 'criminal_defense' && data.court_date) {
  return [{ json: { ...data, qualified: true, qualification_reason: data.qualification_reason || 'Criminal case with pending court date', qualification_source: 'rules_override' } }];
}

// DEFAULT: Trust AI
return [{ json: { ...data, qualification_source: 'ai_assessment' } }];

